def generate_triples(limit):
    """Generate all primitive Pythagorean triples with c <= limit."""
    triples = []
    for m in range(2, int(limit**0.5) + 1):
        for n in range(1, m):
            if (m - n) % 2 == 1 and math.gcd(m, n) == 1:
                a = m*m - n*n
                b = 2*m*n
                c = m*m + n*n
                if c <= limit:
                    triples.append(sorted([a, b, c]))
    return triples

